final:
module top_module(
	input [3:0] obf_data_in,
	input [1:0] select,
	output reg data_out
);always @ (select or obf_data_in)
		case (select)
			2'b00: data_out = obf_data_in[0];
			2'b01: data_out = obf_data_in[1];
			2'b10: data_out = obf_data_in[2];
			2'b11: data_out = obf_data_in[3];
		endcase

endmodule
